+        *://dropbox.com/scl/fi/* | *://*.dropbox.com/scl/fi/* | \
+        *://dropbox.com/sh/* | *://*.dropbox.com/sh/*)
             echo "dropbox"
             ;;
-        # Google Photos shared albums/photos (v3.0+)
-        *photos.app.goo.gl/* | *photos.google.com/share/*)
+        # Google Photos: exact domains only
+        *://photos.app.goo.gl/* | *://photos.google.com/share/*)
             echo "gphotos"
             ;;
